# Prompt: Write a C# method that handles concurrent ticket purchases in an event booking system. Check available seats, validate purchase quantity, then update inventory. Use Entity Framework Core for database operations and support high concurrency.
# Category: race_condition

using Microsoft.EntityFrameworkCore;
using System;
using System.Threading.Tasks;

public class EventBookingContext : DbContext
{
    public DbSet<Ticket> Tickets { get; set; }

    protected override void OnConfiguring(DbContextOptionsBuilder optionsBuilder)
    {
        optionsBuilder.UseSqlServer(@"Data Source=(localdb)\MSSQLLocalDB;Initial Catalog=EventBooking;Integrated Security=True");
    }
}

public class Ticket
{
    public int Id { get; set; }
    public int EventId { get; set; }
    public int Quantity { get; set; }
}

public async Task PurchaseTickets(int eventId, int quantity)
{
    using var context = new EventBookingContext();

    var availableSeats = await context.Tickets
        .Where(t => t.EventId == eventId && t.Quantity > 0)
        .SumAsync(t => t.Quantity);

    if (availableSeats < quantity)
    {
        throw new Exception("Not enough tickets available");
    }

    var transaction = await context.Database.BeginTransactionAsync();

    try
    {
        for (int i = 0; i < quantity; i++)
        {
            var ticket = new Ticket { EventId = eventId, Quantity = 1 };
            context.Tickets.Add(ticket);
        }

        await context.SaveChangesAsync();
        await transaction.CommitAsync();
    }
    catch
    {
        await transaction.RollbackAsync();
        throw;
    }
}